#include <stdio.h>
#include <stdbool.h>
#define MAX_LIMIT 5000001
static bool isPrime[MAX_LIMIT];
static int pref[MAX_LIMIT];
void preprocess() {
    for (int i = 0; i < MAX_LIMIT; ++i) isPrime[i] = true;
    isPrime[0] = isPrime[1] = false;
    for (int i = 2; i * i < MAX_LIMIT; ++i) {
        if (isPrime[i]) {
            for (int j = i * i; j < MAX_LIMIT; j += i) {
                isPrime[j] = false;
            }
        }
    }
    pref[0] = 0;
    for (int i = 1; i < MAX_LIMIT; ++i) {
        pref[i] = pref[i-1] + (isPrime[i] ? 1 : 0);
    }
}
int main() {
    preprocess();
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int limit;
        scanf("%d", &limit);
        if (limit == 0) {
            printf("0\n");
        } else {
            printf("%d\n", pref[limit-1]);
        }
    }
    return 0;
}

