import java.io.*;
import java.util.*;
public class Main {
    private static final int MAX_LIMIT = 5000001;
    private static final boolean[] isPrime = new boolean[MAX_LIMIT];
    private static final int[] pref = new int[MAX_LIMIT];
    private static void preprocess() {
        Arrays.fill(isPrime, true);
        isPrime[0] = isPrime[1] = false;
        for (int i = 2; i * i < MAX_LIMIT; ++i) {
            if (isPrime[i]) {
                for (int j = i * i; j < MAX_LIMIT; j += i) isPrime[j] = false;
            }
        }
        pref[0] = 0;
        for (int i = 1; i < MAX_LIMIT; ++i) {
            pref[i] = pref[i-1] + (isPrime[i] ? 1 : 0);
        }
    }
    public static void main(String[] args) throws Exception {
        preprocess();
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder sb = new StringBuilder();
        for (int t = 0; t < T; ++t) {
            int limit = Integer.parseInt(br.readLine().trim());
            if (limit == 0) sb.append(0);
            else sb.append(pref[limit-1]);
            sb.append('\n');
        }
        System.out.print(sb.toString());
    }
}

code.Python3:
import sys
MAX_LIMIT = 5000001
is_prime = [True] * MAX_LIMIT
is_prime[0] = is_prime[1] = False
for i in range(2, int(MAX_LIMIT ** 0.5) + 1):
    if is_prime[i]:
        step = i
        start = i * i
        is_prime[start:MAX_LIMIT:step] = [False] * ((MAX_LIMIT - start - 1) // step + 1)
# prefix where pref[i] = number of primes <= i
pref = [0] * MAX_LIMIT
cnt = 0
for i in range(MAX_LIMIT):
    if is_prime[i]:
        cnt += 1
    pref[i] = cnt

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        limit = int(next(it))
        if limit == 0:
            out.append('0')
        else:
            out.append(str(pref[limit-1]))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

